6_9.jpg\",\"width\":1136,\"height\":639,\"fallback\":true},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/71a/8ec88564-616d-465d-979a-53eae342571a_106151_TABLET_LANDSCAPE_LARGE_16_9.jpg\",\"width\":2048,\"height\":1152,\"fallback\":true},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/71a/8ec88564-616d-465d-979a-53eae342571a_106151_RETINA_PORTRAIT_16_9.jpg\",\"width\":640,\"height\":360,\"fallback\":true},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/71a/8ec88564-616d-465d-979a-53eae342571a_106151_RECOMENDATION_16_9.jpg\",\"width\":100,\"height\":56,\"fallback\":true}],\"classifications\":[{\"primary\":true,\"segment\":{\"id\":\"KZFzniwnSyZfZ7v7na\",\"name\":\"Arts & Theatre\"},\"genre\":{\"id\":\"KnvZfZ7v7nE\",\"name\":\"Cultural\"},\"subGenre\":{\"id\":\"KZazBEonSMnZfZ7v7nt\",\"name\":\"Cultural\"},\"type\":{\"id\":\"KZAyXgnZfZ7v7nI\",\"name\":\"Undefined\"},\"subType\":{\"id\":\"KZFzBErXgnZfZ7v7lJ\",\"name\":\"Undefined\"},\"family\":false}],\"upcomingEvents\":{\"universe\":893,\"_total\":893,\"_filtered\":0},\"_links\":{\"self\":{\"href\":\"/discovery/v2/attractions/K8vZ917ry37?locale=en-us\"}}}]}},{\"name\":\"Un paseo por Madrid\",\"type\":\"event\",\"id\":\"LvZ18QbUICJBaJOZvvqGZ\",\"test\":false,\"description\":\" \\n¿Estás listo para un paseo que se baila?\\nManuel no es un guía turístico.\\nEs un aspirante a escritor con un diario comprado en la papelería de la esquina que, sin pedir permiso, se convierte en un portal mágico por las calles de Madrid.\\nAquí la cordura se queda en casa.\\nEste tributo musical es una bomba de canciones, humor, pasión y torpeza, donde la poesía se mezcla con confesiones, risas inesperadas y conversaciones imposibles con sus ídolos literarios: Hemingway, Cortázar y Lorca… pero en versión canalla y con ritmo.\\nUn espectáculo íntimo, vibrante y muy vivo, que te hará reír, emocionarte y salir con la sensación de que, a veces, la vida se escribe mejor bailándola que intentando entenderla.\",\"url\":\"https://www.universe.com/events/un-paseo-por-madrid-tickets-32JG7D?ref=ticketmaster\",\"locale\":\"en-us\",\"images\":[{\"ratio\":\"3_2\",\"url\":\"https://images.universe.com/2be3f10f-4f47-48ea-a5dc-9531e88f325a/-/format/jpeg/-/scale_crop/305x203/center/-/progressive/yes/-/inline/yes/\",\"width\":305,\"height\":203,\"fallback\":false},{\"ratio\":\"16_9\",\"url\":\"https://images.universe.com/2be3f10f-4f47-48ea-a5dc-9531e88f325a/-/format/jpeg/-/scale_crop/1024x576/center/-/progressive/yes/-/inline/yes/\",\"width\":1024,\"height\":576,\"fallback\":false},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/f51/ee785ed6-f806-4195-98f4-69f67e09df51_106201_TABLET_LANDSCAPE_LARGE_16_9.jpg\",\"width\":2048,\"height\":1152,\"fallback\":true},{\"ratio\":\"4_3\",\"url\":\"https://images.universe.com/2be3f10f-4f47-48ea-a5dc-9531e88f325a/-/format/jpeg/-/scale_crop/305x225/center/-/progressive/yes/-/inline/yes/\",\"width\":305,\"height\":225,\"fallback\":false},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/f51/ee785ed6-f806-4195-98f4-69f67e09df51_106201_RECOMENDATION_16_9.jpg\",\"width\":100,\"height\":56,\"fallback\":true},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/f51/ee785ed6-f806-4195-98f4-69f67e09df51_106201_RETINA_PORTRAIT_16_9.jpg\",\"width\":640,\"height\":360,\"fallback\":true},{\"ratio\":\"3_2\",\"url\":\"https://images.universe.com/2be3f10f-4f47-48ea-a5dc-9531e88f325a/-/format/jpeg/-/scale_crop/1024x683/center/-/progressive/yes/-/inline/yes/\",\"width\":1024,\"height\":683,\"fallback\":false},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/f51/ee785ed6-f806-4195-98f4-69f67e09df51_106201_EVENT_DETAIL_PAGE_16_9.jpg\",\"width\":205,\"height\":115,\"fallback\":true},{\"ratio\":\"3_2\",\"url\":\"https://images.universe.com/2be3f10f-4f47-48ea-a5dc-9531e88f325a/-/format/jpeg/-/scale_crop/640x427/center/-/progressive/yes/-/inline/yes/\",\"width\":640,\"height\":427,\"fallback\":false},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/f51/ee785ed6-f806-4195-98f4-69f67e09df51_106201_RETINA_LANDSCAPE_16_9.jpg\",\"width\":1136,\"height\":639,\"fallback\":true}],\"sales\":{\"public\":{\"startDateTime\":\"2026-01-28T11:00:31Z\",\"startTBD\":false,\"startTBA\":false,\"endDateTime\":\"2026-03-20T19:40:00Z\"}},\"dates\":{\"access\":{\"startDateTime\":\"2026-01-28T11:00:32Z\",\"startApproximate\":false,\"endDateTime\":\"2026-03-20T19:40:00Z\",\"endApproximate\":false},\"start\":{\"localDate\":\"2026-03-20\",\"localTime\":\"19:30:00\",\"dateTime\":\"2026-03-20T18:30:00Z\",\"dateTBD\":false,\"dateTBA\":false,\"timeTBA\":false,\"noSpecificTime\":false},\"end\":{\"localTime\":\"19:30:00\",\"dateTime\":\"2026-03-20T19:40:00Z\",\"approximate\":false,\"noSpecificTime\":false},\"timezone\":\"Europe/Madrid\",\"status\":{\"code\":\"onsale\"},\"spanMultipleDays\":false},\"classifications\":[{\"segment\":{\"id\":\"KZFzniwnSyZfZ7v7nl\",\"name\":\"Undefined\"},\"family\":false}],\"nameOrigin\":\"custom\",\"_links\":{\"self\":{\"href\":\"/discovery/v2/events/LvZ18QbUICJBaJOZvvqGZ?locale=en-us\"},\"venues\":[{\"href\":\"/discovery/v2/venues/Z598xZ2qZavd1?locale=en-us\"}]},\"_embedded\":{\"venues\":[{\"name\":\"Espacio Broadway\",\"type\":\"venue\",\"id\":\"Z598xZ2qZavd1\",\"test\":false,\"url\":\"https://www.ticketmaster.es/venue/espacio-broadway-madrid-entradas/esbroadmad/104\",\"locale\":\"en-us\",\"images\":[{\"ratio\":\"16_9\",\"url\":\"https://media.ticketmaster.eu/spain/8543c5f22479e0c028f124ddce8bd358.png\",\"width\":205,\"height\":115,\"fallback\":false}],\"postalCode\":\"28015\",\"timezone\":\"Europe/Madrid\",\"city\":{\"name\":\"Madrid\"},\"state\":{\"name\":\"Madrid\"},\"country\":{\"name\":\"Spain\",\"countryCode\":\"ES\"},\"address\":{\"line1\":\" C. de San Vicente Ferrer, 55\"},\"location\":{\"longitude\":\"-3.70785\",\"latitude\":\"40.42605\"},\"upcomingEvents\":{\"universe\":68,\"_total\":68,\"_filtered\":0},\"_links\":{\"self\":{\"href\":\"/discovery/v2/venues/Z598xZ2qZavd1?locale=en-us\"}}}]}},{\"name\":\"Tablao Flamenco 1911: El Tablao Más Antiguo del Mundo\",\"type\":\"event\",\"id\":\"LvZ18Qbc8EkDV-ZZv9onZ\",\"test\":false,\"description\":\"En Madrid hay muchos tablaos, pero la jerarquía existe. El Tablao Flamenco 1911 (antiguo Villa Rosa) no solo es el más antiguo del mundo; es el más exigente. Su escenario es sagrado: por aquí han pasado desde Antonio Chacón hasta Imperio Argentina, y esa historia impone un nivel que otros locales no pueden igualar.\\n\\nPor qué nuestra calidad artística es superior:\\n\\nEl Escenario de la Élite: Nuestro elenco no es fijo ni rutinario. Contratamos rotativamente a primeras figuras nacionales, solistas que llenan teatros y ganadores de los premios más prestigiosos del flamenco (Premio Nacional, Desplante de las Minas, etc.).\\nSin Guiones, Pura Verdad: A diferencia de los espectáculos para turistas que repiten coreografías mecánicas, aquí se respira improvisación, técnica depurada y \\\"duende\\\" real. Es flamenco de entendidos, explicado para que usted lo sienta.\\nLa Acústica de la Catedral: Nuestros arcos de estilo Alhambra no son solo decoración; crean una sonoridad natural perfecta que permite apreciar el rasgueo de la guitarra y el quejío del cantaor sin distorsiones.\\n\\nLa Experiencia Completa: Mientras disfruta del mejor espectáculo de la ciudad, le regalamos 1 copa de bienvenida y le invitamos a que deguste nuestra selección de Tapas Ibéricas (Jamón, Queso, Tortilla Española). Sin cenas pesadas que distraigan del arte; solo sabor auténtico.\",\"url\":\"https://www.universe.com/events/tablao-flamenco-1911-el-tablao-mas-antiguo-del-mundo-tickets-96BY2G?ref=ticketmaster\",\"locale\":\"en-us\",\"images\":[{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/548/5fefbd1c-973b-4b0e-9b2e-d78e4ce37548_106111_TABLET_LANDSCAPE_LARGE_16_9.jpg\",\"width\":2048,\"height\":1152,\"fallback\":true},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/548/5fefbd1c-973b-4b0e-9b2e-d78e4ce37548_106111_EVENT_DETAIL_PAGE_16_9.jpg\",\"width\":205,\"height\":115,\"fallback\":true},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/548/5fefbd1c-973b-4b0e-9b2e-d78e4ce37548_106111_RETINA_PORTRAIT_16_9.jpg\",\"width\":640,\"height\":360,\"fallback\":true},{\"ratio\":\"3_2\",\"url\":\"https://images.universe.com/efd2b4ee-1942-4f14-90f5-a22cfcc918a1/-/format/jpeg/-/scale_crop/1024x683/center/-/progressive/yes/-/inline/yes/\",\"width\":1024,\"height\":683,\"fallback\":false},{\"ratio\":\"3_2\",\"url\":\"https://images.universe.com/efd2b4ee-1942-4f14-90f5-a22cfcc918a1/-/format/jpeg/-/scale_crop/640x427/center/-/progressive/yes/-/inline/yes/\",\"width\":640,\"height\":427,\"fallback\":false},{\"ratio\":\"16_9\",\"url\":\"https://images.universe.com/efd2b4ee-1942-4f14-90f5-a22cfcc918a1/-/format/jpeg/-/scale_crop/1024x576/center/-/progressive/yes/-/inline/yes/\",\"width\":1024,\"height\":576,\"fallback\":false},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/548/5fefbd1c-973b-4b0e-9b2e-d78e4ce37548_106111_RECOMENDATION_16_9.jpg\",\"width\":100,\"height\":56,\"fallback\":true},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/548/5fefbd1c-973b-4b0e-9b2e-d78e4ce37548_106111_RETINA_LANDSCAPE_16_9.jpg\",\"width\":1136,\"height\":639,\"fallback\":true},{\"ratio\":\"3_2\",\"url\":\"https://images.universe.com/efd2b4ee-1942-4f14-90f5-a22cfcc918a1/-/format/jpeg/-/scale_crop/305x203/center/-/progressive/yes/-/inline/yes/\",\"width\":305,\"height\":203,\"fallback\":false},{\"ratio\":\"4_3\",\"url\":\"https://images.universe.com/efd2b4ee-1942-4f14-90f5-a22cfcc918a1/-/format/jpeg/-/scale_crop/305x225/center/-/progressive/yes/-/inline/yes/\",\"width\":305,\"height\":225,\"fallback\":false}],\"sales\":{\"public\":{\"startDateTime\":\"2026-02-10T15:36:59Z\",\"startTBD\":false,\"startTBA\":false,\"endDateTime\":\"2026-03-20T19:30:00Z\"}},\"dates\":{\"access\":{\"startDateTime\":\"2026-02-18T10:41:26Z\",\"startApproximate\":false,\"endDateTime\":\"2026-03-20T19:30:00Z\",\"endApproximate\":false},\"start\":{\"localDate\":\"2026-03-20\",\"localTime\":\"19:30:00\",\"dateTime\":\"2026-03-20T18:30:00Z\",\"dateTBD\":false,\"dateTBA\":false,\"timeTBA\":false,\"noSpecificTime\":false},\"end\":{\"localTime\":\"19:30:00\",\"dateTime\":\"2026-03-20T19:30:00Z\",\"approximate\":false,\"noSpecificTime\":false},\"timezone\":\"Europe/Madrid\",\"status\":{\"code\":\"onsale\"},\"spanMultipleDays\":false},\"classifications\":[{\"segment\":{\"id\":\"KZFzniwnSyZfZ7v7nJ\",\"name\":\"Music\"},\"genre\":{\"id\":\"KnvZfZ7vAeF\",\"name\":\"World\"},\"subGenre\":{\"id\":\"KZazBEonSMnZfZ7v6ln\",\"name\":\"Flamenco\"},\"family\":false}],\"nameOrigin\":\"custom\",\"_links\":{\"self\":{\"href\":\"/discovery/v2/events/LvZ18Qbc8EkDV-ZZv9onZ?locale=en-us\"},\"attractions\":[{\"href\":\"/discovery/v2/attractions/K8vZ917L9C0?locale=en-us\"}],\"venues\":[{\"href\":\"/discovery/v2/venues/Z598xZ2qZav1k?locale=en-us\"}]},\"_embedded\":{\"venues\":[{\"name\":\"Tablao Flamenco 1911\",\"type\":\"venue\",\"id\":\"Z598xZ2qZav1k\",\"test\":false,\"url\":\"https://www.ticketmaster.es/venue/tablao-flamenco-1911-madrid-entradas/tbf1911mad/112\",\"locale\":\"en-us\",\"images\":[{\"ratio\":\"16_9\",\"url\":\"https://media.ticketmaster.eu/spain/f4deed1526231b2d500765fb9e3a5f15.jpg\",\"width\":205,\"height\":115,\"fallback\":false}],\"postalCode\":\"28012\",\"timezone\":\"Europe/Madrid\",\"city\":{\"name\":\"Madrid\"},\"state\":{\"name\":\"Madrid\"},\"country\":{\"name\":\"Spain\",\"countryCode\":\"ES\"},\"address\":{\"line1\":\"Pl. de Sta. Ana, 15, Centro,\"},\"location\":{\"longitude\":\"1.56931\",\"latitude\":\"41.38152\"},\"upcomingEvents\":{\"universe\":1874,\"_total\":1874,\"_filtered\":0},\"_links\":{\"self\":{\"href\":\"/discovery/v2/venues/Z598xZ2qZav1k?locale=en-us\"}}}],\"attractions\":[{\"name\":\"Tablao Flamenco 1911\",\"type\":\"attraction\",\"id\":\"K8vZ917L9C0\",\"test\":false,\"url\":\"https://www.ticketmaster.com/tablao-flamenco-1911-tickets/artist/4230554\",\"loc