115,\"fallback\":true},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/548/5fefbd1c-973b-4b0e-9b2e-d78e4ce37548_106111_RETINA_PORTRAIT_16_9.jpg\",\"width\":640,\"height\":360,\"fallback\":true},{\"ratio\":\"4_3\",\"url\":\"https://s1.ticketm.net/dam/c/548/5fefbd1c-973b-4b0e-9b2e-d78e4ce37548_106111_CUSTOM.jpg\",\"width\":305,\"height\":225,\"fallback\":true},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/548/5fefbd1c-973b-4b0e-9b2e-d78e4ce37548_106111_RECOMENDATION_16_9.jpg\",\"width\":100,\"height\":56,\"fallback\":true},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/548/5fefbd1c-973b-4b0e-9b2e-d78e4ce37548_106111_TABLET_LANDSCAPE_16_9.jpg\",\"width\":1024,\"height\":576,\"fallback\":true},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/548/5fefbd1c-973b-4b0e-9b2e-d78e4ce37548_106111_RETINA_LANDSCAPE_16_9.jpg\",\"width\":1136,\"height\":639,\"fallback\":true},{\"ratio\":\"3_2\",\"url\":\"https://s1.ticketm.net/dam/c/548/5fefbd1c-973b-4b0e-9b2e-d78e4ce37548_106111_RETINA_PORTRAIT_3_2.jpg\",\"width\":640,\"height\":427,\"fallback\":true}],\"classifications\":[{\"primary\":true,\"segment\":{\"id\":\"KZFzniwnSyZfZ7v7nJ\",\"name\":\"Music\"},\"genre\":{\"id\":\"KnvZfZ7vAeF\",\"name\":\"World\"},\"subGenre\":{\"id\":\"KZazBEonSMnZfZ7v6ln\",\"name\":\"Flamenco\"},\"type\":{\"id\":\"KZAyXgnZfZ7v7nI\",\"name\":\"Undefined\"},\"subType\":{\"id\":\"KZFzBErXgnZfZ7v7lJ\",\"name\":\"Undefined\"},\"family\":false}],\"upcomingEvents\":{\"universe\":1848,\"_total\":1848,\"_filtered\":0},\"_links\":{\"self\":{\"href\":\"/discovery/v2/attractions/K8vZ917L9C0?locale=en-us\"}}}]}},{\"name\":\"IMPRO IMPAR SHOW\",\"type\":\"event\",\"id\":\"LvZ18QbwaU0oLM8Zv_e2V\",\"test\":false,\"description\":\" \\nImpro Impar Show es un espectáculo de improvisación divertido, pensado para ti, ya sea que desees participar o simplemente disfrutar desde tu butaca. Todo lo que ocurre en el escenario es completamente improvisado e inventado al momento, y se basa en las ideas que el público propone, lo que convierte a cada representación en una experiencia única y personal.\\nNo sabemos exactamente lo que va a suceder, pero contamos con la participación del público para dar vida a la actuación. Apostamos por un escenario vacío que nos permite jugar y volar creativamente, siempre acompañados de buena música y, sobre todo, de ti. Te aseguramos que saldrás de este espectáculo con una sonrisa en el rostro y un corazón lleno de risas.\\n¡Ven a disfrutar de Impro Impar Show y sé parte de la diversión!\",\"url\":\"https://www.universe.com/events/impro-impar-show-tickets-RLQ2VB?ref=ticketmaster\",\"locale\":\"en-us\",\"images\":[{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/f51/ee785ed6-f806-4195-98f4-69f67e09df51_106201_TABLET_LANDSCAPE_LARGE_16_9.jpg\",\"width\":2048,\"height\":1152,\"fallback\":true},{\"ratio\":\"3_2\",\"url\":\"https://images.universe.com/f7a8c11a-92b8-4ee1-b8b5-411cd553a03c/-/format/jpeg/-/scale_crop/640x427/center/-/progressive/yes/-/inline/yes/\",\"width\":640,\"height\":427,\"fallback\":false},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/f51/ee785ed6-f806-4195-98f4-69f67e09df51_106201_RECOMENDATION_16_9.jpg\",\"width\":100,\"height\":56,\"fallback\":true},{\"ratio\":\"3_2\",\"url\":\"https://images.universe.com/f7a8c11a-92b8-4ee1-b8b5-411cd553a03c/-/format/jpeg/-/scale_crop/1024x683/center/-/progressive/yes/-/inline/yes/\",\"width\":1024,\"height\":683,\"fallback\":false},{\"ratio\":\"16_9\",\"url\":\"https://images.universe.com/f7a8c11a-92b8-4ee1-b8b5-411cd553a03c/-/format/jpeg/-/scale_crop/1024x576/center/-/progressive/yes/-/inline/yes/\",\"width\":1024,\"height\":576,\"fallback\":false},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/f51/ee785ed6-f806-4195-98f4-69f67e09df51_106201_RETINA_PORTRAIT_16_9.jpg\",\"width\":640,\"height\":360,\"fallback\":true},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/f51/ee785ed6-f806-4195-98f4-69f67e09df51_106201_EVENT_