ter.eu/spain/8543c5f22479e0c028f124ddce8bd358.png\",\"width\":205,\"height\":115,\"fallback\":false}],\"postalCode\":\"28015\",\"timezone\":\"Europe/Madrid\",\"city\":{\"name\":\"Madrid\"},\"state\":{\"name\":\"Madrid\"},\"country\":{\"name\":\"Spain\",\"countryCode\":\"ES\"},\"address\":{\"line1\":\" C. de San Vicente Ferrer, 55\"},\"location\":{\"longitude\":\"-3.70785\",\"latitude\":\"40.42605\"},\"upcomingEvents\":{\"universe\":59,\"_total\":59,\"_filtered\":0},\"_links\":{\"self\":{\"href\":\"/discovery/v2/venues/Z598xZ2qZavd1?locale=en-us\"}}}]}},{\"name\":\"WOW PEPI!\",\"type\":\"event\",\"id\":\"LvZ18QQldFeTxDYZvcClL\",\"test\":false,\"description\":\"  BIENVENIDES A WOW PEPI!\\n\\nUna experiencia donde el escenario se convierte en tablero y el público en protagonista. \\nEste espectáculo interactivo es una celebración del ingenio, la música y el desenfado, donde cada asistente tiene la oportunidad de brillar.\\n\\nDesafíos de karaoke trabalenguas y preguntas ingeniosas, entre otros, son los retos que encenderán la energía de la sala y te transformará en parte esencial del espectáculo.\\n\\nGuiando esta fiesta se encuentra Antonia de Latex, maestra de ceremonias incomparable, cuya presencia magnética, carisma arrollador y afilado sentido del humor convierten cada momento en una explosión de glamour y cercanía.\\n\\nUn juego, una fiesta, un espectáculo donde la risa, la música y la participación se entrelazan para crear una experiencia única e irrepetible.\",\"url\":\"https://www.universe.com/events/wow-pepi-tickets-C76QZP?ref=ticketmaster\",\"locale\":\"en-us\",\"images\":[{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/f51/ee785ed6-f806-4195-98f4-69f67e09df51_106201_TABLET_LANDSCAPE_LARGE_16_9.jpg\",\"width\":2048,\"height\":1152,\"fallback\":true},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/f51/ee785ed6-f806-4195-98f4-69f67e09df51_106201_RECOMENDATION_16_9.jpg\",\"width\":100,\"height\":56,\"fallback\":true},{\"ratio\":\"4_3\",\"u