lassifications\":[{\"segment\":{\"id\":\"KZFzniwnSyZfZ7v7nl\",\"name\":\"Undefined\"},\"family\":false}],\"nameOrigin\":\"custom\",\"_links\":{\"self\":{\"href\":\"/discovery/v2/events/LvZ18QQp1iaebc8Zv0bYw?locale=en-us\"},\"venues\":[{\"href\":\"/discovery/v2/venues/Z598xZ2qZav7k?locale=en-us\"}]},\"_embedded\":{\"venues\":[{\"name\":\"Espacio Hollywood\",\"type\":\"venue\",\"id\":\"Z598xZ2qZav7k\",\"test\":false,\"url\":\"https://www.ticketmaster.es/venue/espacio-hollywood-madrid-entradas/eshollymad/114\",\"locale\":\"en-us\",\"images\":[{\"ratio\":\"16_9\",\"url\":\"https://media.ticketmaster.eu/spain/0e2df2d92cd77fd19c037115cc5305c7.png\",\"width\":205,\"height\":115,\"fallback\":false}],\"postalCode\":\"28014\",\"timezone\":\"Europe/Madrid\",\"city\":{\"name\":\"Madrid\"},\"state\":{\"name\":\"Madrid\"},\"country\":{\"name\":\"Spain\",\"countryCode\":\"ES\"},\"address\":{\"line1\":\" C. del Infante, 3\"},\"location\":{\"longitude\":\"-3.6992\",\"latitude\":\"40.41434\"},\"upcomingEvents\":{\"universe\":54,\"_total\":54,\"_filtered\":0},\"_links\":{\"self\":{\"href\":\"/discovery/v2/venues/Z598xZ2qZav7k?locale=en-us\"}}}]}},{\"name\":\"Broadway Comedy Club\",\"type\":\"event\",\"id\":\"LvZ18Q_gm58JU0OZvSACf\",\"test\":false,\"description\":\" Welcome to Broadway Comedy Club!\\n\\nLa semana no es tan dura si el jueves haces una parada en Espacio Broadway.\\n\\nEste show es como un circo de monólogos, pero sin animales, salvo los cómicos, que a veces se descontrolan.\\nPresentado por David Rodri, que cada noche invita a tres cómicos a subir al escenario a contagiarnos su buen rollo. Cada cómico trae su propio estilo: humor cotidiano, humor negro, humor absurdo... Pide tu bebida favorita en la barra de Espacio Broadway y déjate sorprender con cada número.\\n\\nLos jueves a las 21:00, Espacio Broadway, la ya mítica sala de espectáculos y tributos de Malasaña, se transforma en un auténtico laboratorio de la risa. Tres cómicos vendrán a contar sus historias, probar sus chistes, contar verdades (o mentiras, pero bien contadas). Y todos llevados de la manita de David Rodri, cómico y psicólogo, curtido en el arte de provocar la risa. ¡Y lo mejor de todo es que puedes repetir, no habrá dos días iguales!\",\"url\":\"https://www.universe.com/events/broadway-comedy-club-tickets-SC9M0Z?ref=ticketmaster\",\"locale\":\"en-us\",\"images\":[{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/f51/ee785ed6-f806-4195-98f4-69f67e09df51_106201_TABLET_LANDSCAPE_LARGE_16_9.jpg\",\"width\":2048,\"height\":1152,\"fallback\":true},{\"ratio\":\"3_2\",\"url\":\"https://images.universe.com/809ac2ac-2c09-452b-8d94-c3777a8640eb/-/format/jpeg/-/scale_crop/640x427/center/-/progressive/yes/-/inline/yes/\",\"width\":640,\"height\":427,\"fallback\":false},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/f51/ee785ed6-f806-4195-98f4-69f67e09df51_106201_RECOMENDATION_16_9.jpg\",\"width\":100,\"height\":56,\"fallback\":true},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/f51/ee785ed6-f806-4195-98f4-69f67e09df51_106201_RETINA_PORTRAIT_16_9.jpg\",\"width\":640,\"height\":360,\"fallback\":true},{\"ratio\":\"16_9\",\"url\":\"https://images.universe.com/809ac2ac-2c09-452b-8d94-c3777a8640eb/-/format/jpeg/-/scale_crop/1024x576/center/-/progressive/yes/-/inline/yes/\",\"width\":1024,\"height\":576,\"fallback\":false},{\"ratio\":\"3_2\",\"url\":\"https://images.universe.com/809ac2ac-2c09-452b-8d94-c3777a8640eb/-/format/jpeg/-/scale_crop/1024x683/center/-/progressive/yes/-/inline/yes/\",\"width\":1024,\"height\":683,\"fallback\":false},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/f51/ee785ed6-f806-4195-98f4-69f67e09df51_106201_EVENT_DETAIL_PAGE_16_9.jpg\",\"width\":205,\"height\":115,\"fallback\":true},{\"ratio\":\"3_2\",\"url\":\"https://images.universe.com/809ac2ac-2c09-452b-8d94-c3777a8640eb/-/format/jpeg/-/scale_crop/305x203/center/-/progressive/yes/-/inline/yes/\",\"width\":305,\"height\":203,\"fallback\":false},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/f51/ee785ed6-f806-4195-98f4-69f67e09df51_106201_RETINA_LANDSCAPE_16_9.jpg\",\"width\":1136,\"height\":639,\"fallback\":true},{\"ratio\":\"4_3\",\"url\":\"https://images.universe.com/809ac2ac-2c09-452b-8d94-c3777a8640eb/-/format/jpeg/-/scale_crop/305x225/center/-/progressive/yes/-/inline/yes/\",\"width\":305,\"height\":225,\"fallback\":false}],\"sales\":{\"public\":{\"startDateTime\":\"2026-02-24T09:23:57Z\",\"startTBD\":false,\"startTBA\":false,\"endDateTime\":\"2026-03-26T21:15:00Z\"}},\"dates\":{\"access\":{\"startDateTime\":\"2026-02-24T09:23:58Z\",\"startApproximate\":false,\"endDateTime\":\"2026-03-26T21:15:00Z\",\"endApproximate\":false},\"start\":{\"localDate\":\"2026-03-26\",\"localTime\":\"21:00:00\",\"dateTime\":\"2026-03-26T20:00:00Z\",\"dateTBD\":false,\"dateTBA\":false,\"timeTBA\":false,\"noSpecificTime\":false},\"end\":{\"localTime\":\"21:00:00\",\"dateTime\":\"2026-03-26T21:15:00Z\",\"approximate\":false,\"noSpecificTime\":false},\"timezone\":\"Europe/Madrid\",\"status\":{\"code\":\"onsale\"},\"spanMultipleDays\":false},\"classifications\":[{\"segment\":{\"id\":\"KZFzniwnSyZfZ7v7nl\",\"name\":\"Undefined\"},\"family\":false}],\"nameOrigin\":\"custom\",\"_links\":{\"self\":{\"href\":\"/discovery/v2/events/LvZ18Q_gm58JU0OZvSACf?locale=en-us\"},\"venues\":[{\"href\":\"/discovery/v2/venues/Z598xZ2qZavd1?locale=en-us\"}]},\"_embedded\":{\"venues\":[{\"name\":\"Espacio Broadway\",\"type\":\"venue\",\"id\":\"Z598xZ2qZavd1\",\"test\":false,\"url\":\"https://www.ticketmaster.es/venue/espacio-broadway-madrid-entradas/esbroadmad/104\",\"locale\":\"en-us\",\"images\":[{\"ratio\":\"16_9\",\"url\":\"https://media.ticketmaster.eu/spain/8543c5f22479e0c028f124ddce8bd358.png\",\"width\":205,\"height\":115,\"fallback\":false}],\"postalCode\":\"28015\",\"timezone\":\"Europe/Madrid\",\"city\":{\"name\":\"Madrid\"},\"state\":{\"name\":\"Madrid\"},\"country\":{\"name\":\"Spain\",\"countryCode\":\"ES\"},\"address\":{\"line1\":\" C. de San Vicente Ferrer, 55\"},\"location\":{\"longitude\":\"-3.70785\",\"latitude\":\"40.42605\"},\"upcomingEvents\":{\"universe\":59,\"_total\":59,\"_filtered\":0},\"_links\":{\"self\":{\"href\":\"/discovery/v2/venues/Z598xZ2qZavd1?locale=en-us\"}}}]}},{\"name\":\"Tablao Flamenco 1911: El Tablao Más Antiguo del Mundo\",\"type\":\"event\",\"id\":\"LvZ18Qbc8EkDV-ZZv9on_\",\"test\":false,\"description\":\"En Madrid hay muchos tablaos, pero la jerarquía existe. El Tablao Flamenco 1911 (antiguo Villa Rosa) no solo es el más antiguo del mundo; es el más exigente. Su escenario es sagrado: por aquí han pasado desde Antonio Chacón hasta Imperio Argentina, y esa historia impone un nivel que otros locales no pueden igualar.\\n\\nPor qué nuestra calidad artística es superior:\\n\\nEl Escenario de la Élite: Nuestro elenco no es fijo ni rutinario. Contratamos rotativamente a primeras figuras nacionales, solistas que llenan teatros y ganadores de los premios más prestigiosos del flamenco (Premio Nacional, Desplante de las Minas, etc.).\\nSin Guiones, Pura Verdad: A diferencia de los espectáculos para turistas que repiten coreografías mecánicas, aquí se respira improvisación, técnica depurada y \\\"duende\\\" real. Es flamenco de entendidos, explicado para que usted lo sienta.\\nLa Acústica de la Catedral: Nuestros arcos de estilo Alhambra no son solo decoración; crean una sonoridad natural perfecta que permite apreciar el rasgueo de la guitarra y el quejío del cantaor sin distorsiones.\\n\\nLa Experiencia Completa: Mientras disfruta del mejor espectáculo de la ciudad, le regalamos 1 copa de bienvenida y le invitamos a que deguste nuestra selección de Tapas Ibéricas (Jamón, Queso, Tortilla Española). Sin cenas pesadas que distraigan del arte; solo sabor auténtico.\",\"url\":\"https://www.universe.com/events/tablao-flamenco-1911-el-tablao-mas-antiguo-del-mundo-tickets-96BY2G?ref=ticketmaster\",\"locale\":\"en-us\",\"images\":[{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/548/5fefbd1c-973b-4b0e-9b2e-d78e4ce37548_106111_TABLET_LANDSCAPE_LARGE_16_9.jpg\",\"width\":2048,\"height\":1152,\"fallback\":true},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/548/5fefbd1c-973b-4b0e-9b2e-d78e4ce37548_106111_EVENT_DETAIL_PAGE_16_9.jpg\",\"width\":205,\"height\":115,\"fallback\":true},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/548/5fefbd1c-973b-4b0e-9b2e-d78e4ce37548_106111_RETINA_PORTRAIT_16_9.jpg\",\"width\":640,\"height\":360,\"fallback\":true},{\"ratio\":\"3_2\",\"url\":\"https://images.universe.com/efd2b4ee-1942-4f14-90f5-a22cfcc918a1/-/format/jpeg/-/scale_crop/1024x683/center/-/progressive/yes/-/inline/yes/\",\"width\":1024,\"height\":683,\"fallback\":false},{\"ratio\":\"3_2\",\"url\":\"https://images.universe.com/efd2b4ee-1942-4f14-90f5-a22cfcc918a1/-/format/jpeg/-/scale_crop/640x427/center/-/progressive/yes/-/inline/yes/\",\"width\":640,\"height\":427,\"fallback\":false},{\"ratio\":\"16_9\",\"url\":\"https://images.universe.com/efd2b4ee-1942-4f14-90f5-a22cfcc918a1/-/format/jpeg/-/scale_crop/1024x576/center/-/progressive/yes/-/inline/yes/\",\"width\":1024,\"height\":576,\"fallback\":false},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/548/5fefbd1c-973b-4b0e-9b2e-d78e4ce37548_106111_RECOMENDATION_16_9.jpg\",\"width\":100,\"height\":56,\"fallback\":true},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/548/5fefbd1c-973b-4b0e-9b2e-d78e4ce37548_106111_RETINA_LANDSCAPE_16_9.jpg\",\"width\":1136,\"height\":639,\"fallback\":true},{\"ratio\":\"3_2\",\"url\":\"https://images.universe.com/efd2b4ee-1942-4f14-90f5-a22cfcc918a1/-/format/jpeg/-/scale_crop/305x203/center/-/progressive/yes/-/inline/yes/\",\"width\":305,\"height\":203,\"fallback\":false},{\"ratio\":\"4_3\",\"url\":\"https://images.universe.com/efd2b4ee-1942-4f14-90f5-a22cfcc918a1/-/format/jpeg/-/scale_crop/305x225/center/-/progressive/yes/-/inline/yes/\",\"width\":305,\"height\":225,\"fallback\":false}],\"sales\":{\"public\":{\"startDate