_9\",\"url\":\"https://s1.ticketm.net/dam/c/548/5fefbd1c-973b-4b0e-9b2e-d78e4ce37548_106111_RETINA_PORTRAIT_16_9.jpg\",\"width\":640,\"height\":360,\"fallback\":true},{\"ratio\":\"4_3\",\"url\":\"https://s1.ticketm.net/dam/c/548/5fefbd1c-973b-4b0e-9b2e-d78e4ce37548_106111_CUSTOM.jpg\",\"width\":305,\"height\":225,\"fallback\":true},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/548/5fefbd1c-973b-4b0e-9b2e-d78e4ce37548_106111_RECOMENDATION_16_9.jpg\",\"width\":100,\"height\":56,\"fallback\":true},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/548/5fefbd1c-973b-4b0e-9b2e-d78e4ce37548_106111_TABLET_LANDSCAPE_16_9.jpg\",\"width\":1024,\"height\":576,\"fallback\":true},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/548/5fefbd1c-973b-4b0e-9b2e-d78e4ce37548_106111_RETINA_LANDSCAPE_16_9.jpg\",\"width\":1136,\"height\":639,\"fallback\":true},{\"ratio\":\"3_2\",\"url\":\"https://s1.ticketm.net/dam/c/548/5fefbd1c-973b-4b0e-9b2e-d78e4ce37548_106111_RETINA_PORTRAIT_3_2.jpg\",\"width\":640,\"height\":427,\"fallback\":true}],\"classifications\":[{\"primary\":true,\"segment\":{\"id\":\"KZFzniwnSyZfZ7v7nJ\",\"name\":\"Music\"},\"genre\":{\"id\":\"KnvZfZ7vAeF\",\"name\":\"World\"},\"subGenre\":{\"id\":\"KZazBEonSMnZfZ7v6ln\",\"name\":\"Flamenco\"},\"type\":{\"id\":\"KZAyXgnZfZ7v7nI\",\"name\":\"Undefined\"},\"subType\":{\"id\":\"KZFzBErXgnZfZ7v7lJ\",\"name\":\"Undefined\"},\"family\":false}],\"upcomingEvents\":{\"universe\":1844,\"_total\":1844,\"_filtered\":0},\"_links\":{\"self\":{\"href\":\"/discovery/v2/attractions/K8vZ917L9C0?locale=en-us\"}}}]}},{\"name\":\"El Sexólogo del Humor\",\"type\":\"event\",\"id\":\"LvZ18QhVwyfhWvZZvVrG2\",\"test\":false,\"description\":\" ¿Quién dijo que hablar de sexo tenía que ser incómodo o aburrido? J. Piqueras te invita a una sesión golfa donde el placer y la risa van de la mano. Un show de comedia e improvisación que desnuda tabúes, explora los secretos inconfesables y convierte las experiencias más calientes (o más vergonzosas) en carcajadas.\\nEn una sociedad donde el sexo sigue siendo un tema tabú, \\nJ. Piqueras, \\\"El Sexólogo del Humor\\\", te guiará por un viaje sin vergüenzas a través del placer y de esos momentos\\nincómodos que todos hemos vivido.\\n\\nTrae a tu pareja para descubrir juntos que el sexo y el humor son tan inseparables como lo sois vosotros. ¿Estáis preparados para una terapia de risas (y quizás algo más)? Próxima sesión golfa en Espacio Hollywood. Reserva ya tu entrada y disfruta del show para parejas más caliente de la noche. No es un requisito venir en pareja, aunque es posible que salgas con una.\",\"url\":\"https://www.universe.com/events/el-sexologo-del-humor-tickets-X4251N?ref=ticketmaster\",\"locale\":\"en-us\",\"images\":[{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/f51/ee785ed6-f806-4195-98f4-69f67e09df51_106201_TABLET_LANDSCAPE_LARGE_16_9.jpg\",\"width\":2048,\"height\":1152,\"fallback\":true},{\"ratio\":\"4_3\",\"url\":\"https://images.universe.com/49d3b9b3-056f-458a-abfa-0ef7ba6b7fcf/-/resize/1200x/-/crop/1200x1200/0,0/-/format/jpeg/-/scale_crop/305x225/center/-/progressive/yes/-/inline/yes/\",\"width\":305,\"height\":225,\"fallback\":false},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/f51/ee785ed6-f806-4195-98f4-69f67e09df51_106201_RECOMENDATION_16_9.jpg\",\"width\":100,\"height\":56,\"fallback\":true},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/f51/ee785ed6-f806-4195-98f4-69f67e09df51_106201_RETINA_PORTRAIT_16_9.jpg\",\"width\":640,\"height\":360,\"fallback\":true},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/f51/ee785ed6-f806-4195-98f4-69f67e09df51_106201_EVENT_DETAIL_PAGE_16_9.jpg\",\"width\":205,\"height\":115,\"fallback\":true},{\"ratio\":\"3_2\",\"url\":\"https://images.universe.com/49d3b9b3-056f-458a-abfa-0ef7ba6b7fcf/-/resize/1200x/-/crop/1200x1200/0,0/-/format/jpeg/-/scale_crop/305x203/center/-/progressive/yes/-/inline/yes/\",\"width\":305,\"height\":203,\"fallback\"