(15, 'Barcelona', '{\"_embedded\":{\"events\":[{\"name\":\"Antarctica Experience\",\"type\":\"event\",\"id\":\"LvZ18Q_UxpTD1yZZvZs8T\",\"test\":false,\"description\":\" Dare to journey to the edge of the world. Antarctica Experience invites you to follow in the footsteps of the explorer and Oscar-winning filmmaker Luc Jacquet, crossing roaring seas and fields of ice through real images filmed in Antarctica. Surrounded by 360° projections, authentic sounds, and breathtaking wildlife, you’ll feel the thrill of discovery and the serenity of untouched nature. It’s more than an exhibition — it’s an expedition into beauty, science, and emotion.\",\"url\":\"https://www.universe.com/events/antarctica-experience-tickets-67BSRN?ref=ticketmaster\",\"locale\":\"en-us\",\"images\":[{\"ratio\":\"3_2\",\"url\":\"https://images.universe.com/a418fc44-b22a-4062-86ac-7f0f64418f7b/-/resize/1200x/-/crop/1200x1200/0,291/-/format/jpeg/-/scale_crop/1024x683/center/-/progressive/yes/-/inline/yes/\",\"width\":1024,\"height\":683,\"fallback\":false},{\"ratio\":\"3_2\",\"url\":\"https://images.universe.com/a418fc44-b22a-4062-86ac-7f0f64418f7b/-/resize/1200x/-/crop/1200x1200/0,291/-/format/jpeg/-/scale_crop/640x427/center/-/progressive/yes/-/inline/yes/\",\"width\":640,\"height\":427,\"fallback\":false},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/368/b70b1d5a-ce61-4ca9-a3c7-3381694ae368_105351_TABLET_LANDSCAPE_LARGE_16_9.jpg\",\"width\":2048,\"height\":1152,\"fallback\":true},{\"ratio\":\"4_3\",\"url\":\"https://images.universe.com/a418fc44-b22a-4062-86ac-7f0f64418f7b/-/resize/1200x/-/crop/1200x1200/0,291/-/format/jpeg/-/scale_crop/305x225/center/-/progressive/yes/-/inline/yes/\",\"width\":305,\"height\":225,\"fallback\":false},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/368/b70b1d5a-ce61-4ca9-a3c7-3381694ae368_105351_RECOMENDATION_16_9.jpg\",\"width\":100,\"height\":56,\"fallback\":true},{\"ratio\":\"16_9\",\"url\":\"https://s1.ticketm.net/dam/c/368/b70b1d5a-ce61-